let ip =
  $json.headers?.['x-forwarded-for']?.split(',')[0].trim() ||
  $json.headers?.['x-real-ip'] ||
  'unknown';

let data = $getWorkflowStaticData('global');

if (!data.requests) {
  data.requests = {};
}

let now = Date.now();
let window = 60 * 1000; 
let limit = 5;

// cleanup starih requestova
for (let key in data.requests) {
  data.requests[key] = data.requests[key].filter(t => now - t < window);
  if (data.requests[key].length === 0) {
    delete data.requests[key];
  }
}

if (!data.requests[ip]) {
  data.requests[ip] = [];
}

data.requests[ip] = data.requests[ip].filter(t => now - t < window);

if (data.requests[ip].length >= limit) {
  return {
    json: {
      error: "RATE_LIMIT_EXCEEDED",
      message: "Too many requests. Try again later.",
      retryAfter: 60
    }
  };
}

data.requests[ip].push(now);

return { json: $json };

